&lt;ul&gt;
	&lt;li style=&quot;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;civilized-&amp;nbsp;&lt;/span&gt;at an advanced stage of social and cultural development.&lt;/li&gt;
	&lt;li style=&quot;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;educated-&amp;nbsp;&lt;/span&gt;who have received education&lt;/li&gt;
