	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;civilized-&amp;nbsp;&lt;/span&gt;शिक्षित और सभ्य&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;educated-&amp;nbsp;&lt;/span&gt;पढ़ा लिखा&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Reasonable&lt;/strong&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;-&amp;nbsp;&lt;/span&gt;उचित&lt;/li&gt;
&lt;/ul&gt;
